from django.urls import path
from . import views

urlpatterns =[
    # Главная страница - список сотрудников
    path('', views.index, name='index'),

    # Страница входа в систему
    path('login/', views.login_view, name='login'),

    # Выход из системы
    path('logout/', views.logout, name='logout'),

    # Добавление нового сотрудника (только для директора)
    path('create/', views.employee_create, name='employee_create'),

    # Редактирование сотрудника
    # 'update/<int:pk>/' - динамический параметр pk (первичный ключ)
    # <int:pk> - захватывает целое число и передает в функцию как pk
    path('update/<int:pk>/', views.employee_update, name='employee_update'),

    # Удаление сотрудника
    path('delete/<int:pk>/', views.employee_delete, name='employee_delete'),
]